// ==================== Local Storage Manager ====================

class LocalStorageManager {
  static LocalStorageManager? _instance;
  static SharedPreferences? _prefs;

  LocalStorageManager._();

  static Future<LocalStorageManager> getInstance() async {
    _instance ??= LocalStorageManager._();
    _prefs ??= await SharedPreferences.getInstance();
    return _instance!;
  }

  SharedPreferences get prefs {
    if (_prefs == null) {
      throw StateError(
          'LocalStorageManager not initialized. Call getInstance() first.');
    }
    return _prefs!;
  }

  // ==================== Auth Tokens ====================

  Future<bool> saveAuthTokens(AuthTokens tokens) async {
    final jsonString = jsonEncode(tokens.toJson());
    return prefs.setString(StorageKeys.authTokens, jsonString);
  }

  AuthTokens? getAuthTokens() {
    final jsonString = prefs.getString(StorageKeys.authTokens);
    if (jsonString == null) return null;
    try {
      final json = jsonDecode(jsonString) as Map<String, dynamic>;
      return AuthTokens.fromJson(json);
    } catch (e) {
      debugPrint('Error parsing auth tokens: $e');
      return null;
    }
  }

  String? getAccessToken() => getAuthTokens()?.accessToken;

  String? getRefreshToken() => getAuthTokens()?.refreshToken;

  bool get isAuthenticated {
    final tokens = getAuthTokens();
    return tokens != null && !tokens.isExpired;
  }

  bool get needsTokenRefresh {
    final tokens = getAuthTokens();
    return tokens != null && tokens.isAboutToExpire && !tokens.isExpired;
  }

  Future<bool> clearAuthTokens() => prefs.remove(StorageKeys.authTokens);

  // ==================== User Profile ====================

  Future<bool> saveUserProfile(UserProfile profile) async {
    final updatedProfile = profile.copyWith(lastUpdated: DateTime.now());
    final jsonString = jsonEncode(updatedProfile.toJson());
    return prefs.setString(StorageKeys.userProfile, jsonString);
  }

  UserProfile? getUserProfile() {
    final jsonString = prefs.getString(StorageKeys.userProfile);
    if (jsonString == null) return null;
    try {
      final json = jsonDecode(jsonString) as Map<String, dynamic>;
      return UserProfile.fromJson(json);
    } catch (e) {
      debugPrint('Error parsing user profile: $e');
      return null;
    }
  }

  Future<bool> updateUserProfileField(
      String field, dynamic value) async {
    final profile = getUserProfile();
    if (profile == null) return false;

    final json = profile.toJson();
    json[field] = value;
    json['lastUpdated'] = DateTime.now().toIso8601String();

    return prefs.setString(StorageKeys.userProfile, jsonEncode(json));
  }

  Future<bool> clearUserProfile() => prefs.remove(StorageKeys.userProfile);

  // ==================== App Config ====================

  Future<bool> saveAppConfig(AppConfig config) async {
    final jsonString = jsonEncode(config.toJson());
    return prefs.setString(StorageKeys.appConfig, jsonString);
  }

  AppConfig? getAppConfig() {
    final jsonString = prefs.getString(StorageKeys.appConfig);
    if (jsonString == null) return null;
    try {
      final json = jsonDecode(jsonString) as Map<String, dynamic>;
      return AppConfig.fromJson(json);
    } catch (e) {
      debugPrint('Error parsing app config: $e');
      return null;
    }
  }

  AppConfig getAppConfigOrDefault() {
    return getAppConfig() ??
        AppConfig(
          apiBaseUrl: 'https://api.example.com',
          appVersion: '1.0.0',
        );
  }

  bool isFeatureEnabled(String featureName) {
    return getAppConfig()?.isFeatureEnabled(featureName) ?? false;
  }

  Future<bool> clearAppConfig() => prefs.remove(StorageKeys.appConfig);

  // ==================== User Preferences ====================

  Future<bool> setThemeMode(String mode) =>
      prefs.setString(StorageKeys.themeMode, mode);

  String getThemeMode() =>
      prefs.getString(StorageKeys.themeMode) ?? 'system';

  ThemeMode getThemeModeEnum() {
    switch (getThemeMode()) {
      case 'light':
        return ThemeMode.light;
      case 'dark':
        return ThemeMode.dark;
      default:
        return ThemeMode.system;
    }
  }

  Future<bool> setLocale(String locale) =>
      prefs.setString(StorageKeys.locale, locale);

  String getLocale() => prefs.getString(StorageKeys.locale) ?? 'en';

  Future<bool> setNotificationsEnabled(bool enabled) =>
      prefs.setBool(StorageKeys.notificationsEnabled, enabled);

  bool getNotificationsEnabled() =>
      prefs.getBool(StorageKeys.notificationsEnabled) ?? true;

  Future<bool> setFontSize(double size) =>
      prefs.setDouble(StorageKeys.fontSize, size);

  double getFontSize() => prefs.getDouble(StorageKeys.fontSize) ?? 14.0;

  Future<bool> setBiometricEnabled(bool enabled) =>
      prefs.setBool(StorageKeys.biometricEnabled, enabled);

  bool getBiometricEnabled() =>
      prefs.getBool(StorageKeys.biometricEnabled) ?? false;

  // ==================== First Launch & Onboarding ====================

  bool get isFirstLaunch =>
      prefs.getBool(StorageKeys.isFirstLaunch) ?? true;

  Future<bool> setFirstLaunchComplete() =>
      prefs.setBool(StorageKeys.isFirstLaunch, false);

  bool get isOnboardingComplete =>
      prefs.getBool(StorageKeys.onboardingComplete) ?? false;

  Future<bool> setOnboardingComplete() =>
      prefs.setBool(StorageKeys.onboardingComplete, true);

  // ==================== Cached Content ====================

  Future<bool> cacheContent(String key, String data,
      {Duration ttl = const Duration(hours: 1)}) async {
    final cached = CachedContent(
      key: key,
      data: data,
      cachedAt: DateTime.now(),
      ttl: ttl,
    );
    final jsonString = jsonEncode(cached.toJson());
    return prefs.setString('${StorageKeys.cachePrefix}$key', jsonString);
  }

  String? getCachedContent(String key) {
    final jsonString =
        prefs.getString('${StorageKeys.cachePrefix}$key');
    if (jsonString == null) return null;
    try {
      final json = jsonDecode(jsonString) as Map<String, dynamic>;
      final cached = CachedContent.fromJson(json);
      if (cached.isExpired) {
        removeCachedContent(key);
        return null;
      }
      return cached.data;
    } catch (e) {
      debugPrint('Error parsing cached content for key $key: $e');
      return null;
    }
  }

  Future<bool> cacheJsonContent(String key, Map<String, dynamic> data,
      {Duration ttl = const Duration(hours: 1)}) {
    return cacheContent(key, jsonEncode(data), ttl: ttl);
  }

  Map<String, dynamic>? getCachedJsonContent(String key) {
    final data = getCachedContent(key);
    if (data == null) return null;
    try {
      return jsonDecode(data) as Map<String, dynamic>;
    } catch (e) {
      debugPrint('Error parsing cached JSON for key $key: $e');
      return null;
    }
  }

  Future<bool> cacheListContent(String key, List<dynamic> data,
      {Duration ttl = const Duration(hours: 1)}) {
    return cacheContent(key, jsonEncode(data), ttl: ttl);
  }

  List<dynamic>? getCachedListContent(String key) {
    final data = getCachedContent(key);
    if (data == null) return null;
    try {
      return jsonDecode(data) as List<dynamic>;
    } catch (e) {
      debugPrint('Error parsing cached list for key $key: $e');
      return null;
    }
  }

  Future<bool> removeCachedContent(String key) =>
      prefs.remove('${StorageKeys.cachePrefix}$key');

  Future<void> clearAllCache() async {
    final keys = prefs
        .getKeys()
        .where((key) => key.startsWith(StorageKeys.cachePrefix));
    for (final key in keys) {
      await prefs.remove(key);
    }
  }

  Future<void> clearExpiredCache() async {
    final keys = prefs
        .getKeys()
        .where((key) => key.startsWith(StorageKeys.cachePrefix));
    for (final key in keys) {
      final jsonString = prefs.getString(key);
      if (jsonString != null) {
        try {
          final json = jsonDecode(jsonString) as Map<String, dynamic>;
          final cached = CachedContent.fromJson(json);
          if (cached.isExpired) {
            await prefs.remove(key);
          }
        } catch (_) {
          await prefs.remove(key);
        }
      }
    }
  }

  // ==================== Offline Data ====================

  Future<bool> saveOfflineData(String key, dynamic data) async {
    final wrapper = {
      'data': data,
      'savedAt': DateTime.now().toIso8601String(),
    };
    return prefs.setString(
        '${StorageKeys.offlineDataPrefix}$key', jsonEncode(wrapper));
  }

  dynamic getOfflineData(String key) {
    final jsonString =
        prefs.getString('${StorageKeys.offlineDataPrefix}$key');
    if (jsonString == null) return null;
    try {
      final wrapper = jsonDecode(jsonString) as Map<String, dynamic>;
      return wrapper['data'];
    } catch (e) {
      debugPrint('Error parsing offline data for key $key: $e');
      return null;
    }
  }

  DateTime? getOfflineDataTimestamp(String key) {
    final jsonString =
        prefs.getString('${StorageKeys.offlineDataPrefix}$key');
    if (jsonString == null) return null;
    try {
      final wrapper = jsonDecode(jsonString) as Map<String, dynamic>;
      return DateTime.parse(wrapper['savedAt'] as String);
    } catch (e) {
      return null;
    }
  }

  Future<bool> removeOfflineData(String key) =>
      prefs.remove('${StorageKeys.offlineDataPrefix}$key');

  Future<void> clearAllOfflineData() async {
    final keys = prefs
        .getKeys()
        .where((key) => key.startsWith(StorageKeys.offlineDataPrefix));
    for (final key in keys) {
      await prefs.remove(key);
    }
  }

  // ==================== Recent Searches ====================

  Future<bool> addRecentSearch(String query, {int maxItems = 20}) async {
    final searches = getRecentSearches();
    searches.remove(query);
    searches.insert(0, query);
    if (searches.length > maxItems) {
      searches.removeRange(maxItems, searches.length);
    }
    return prefs.setStringList(StorageKeys.recentSearches, searches);
  }

  List<String> getRecentSearches() =>
      prefs.getStringList(StorageKeys.recentSearches) ?? [];

  Future<bool> removeRecentSearch(String query) async {
    final searches = getRecentSearches();
    searches.remove(query);
    return prefs.setStringList(StorageKeys.recentSearches, searches);
  }

  Future<bool> clearRecentSearches() =>
      prefs.remove(StorageKeys.recentSearches);

  // ==================== Favorites ====================

  Future<bool> addFavorite(String id) async {
    final favorites = getFavoriteIds();
    if (!favorites.contains(id)) {
      favorites.add(id);
    }
    return prefs.setStringList(StorageKeys.favoriteIds, favorites);
  }

  Future<bool> removeFavorite(String id) async {
    final favorites = getFavoriteIds();
    favorites.remove(id);
    return prefs.setStringList(StorageKeys.favoriteIds, favorites);
  }

  Future<bool> toggleFavorite(String id) async {
    if (isFavorite(id)) {
      return removeFavorite(id);
    } else {
      return addFavorite(id);
    }
  }

  bool isFavorite(String id) => getFavoriteIds().contains(id);

  List<String> getFavoriteIds() =>
      prefs.getStringList(StorageKeys.favoriteIds) ?? [];

  Future<bool> clearFavorites() => prefs.remove(StorageKeys.favoriteIds);

  // ==================== Sync Management ====================

  Future<bool> setLastSyncTime(DateTime time) =>
      prefs.setString(StorageKeys.lastSyncTime, time.toIso8601String());

  DateTime? getLastSyncTime() {
    final timeString = prefs.getString(StorageKeys.lastSyncTime);
    if (timeString == null) return null;
    return DateTime.tryParse(timeString);
  }

  bool needsSync({Duration threshold = const Duration(minutes: 30)}) {
    final lastSync = getLastSyncTime();
    if (lastSync == null) return true;
    return DateTime.now().difference(lastSync) > threshold;
  }

  // ==================== Logout / Clear All ====================

  Future<void> logout() async {
    await clearAuthTokens();
    await clearUserProfile();
    await clearAllCache();
    await clearRecentSearches();
    // Keep preferences like theme, locale, onboarding status
  }

  Future<bool> clearAll() => prefs.clear();

  // ==================== Debug / Utility ====================

  Map<String, String> getAllStoredKeys() {
    final result = <String, String>{};
    for (final key in prefs.getKeys()) {
      final value = prefs.get(key);
      result[key] = value?.toString() ?? 'null';
    }
    return result;
  }

  int get storedKeysCount => prefs.getKeys().length;

  void printAllStoredData() {
    debugPrint('===== Local Storage Data =====');
    debugPrint('Total keys: $storedKeysCount');
    for (final entry in getAllStoredKeys().entries) {
      final displayValue = entry.value.length > 100
          ? '${entry.value.substring(0, 100)}...'
          : entry.value;
      debugPrint('  ${entry.key}: $displayValue');
    }
    debugPrint('==============================');
  }
}

