    final draft = _storage.getOfflineData('draft_message');
    final timestamp = _storage.getOfflineDataTimestamp('articles');

    _setStatus(
      '📱 Offline Data:\n'
      '  Articles: $articles\n'
      '  Draft: $draft\n'
      '  Saved at: $timestamp',
    );
  }

  Future<void> _testSearchAndFavorites() async {
    await _storage.addRecentSearch('Flutter widgets');
    await _storage.addRecentSearch('Dart async');
    await _storage.addRecentSearch('SharedPreferences');
    await _storage.addRecentSearch('State management');

    await _storage.addFavorite('article_1');
    await _storage.addFavorite('article_2');
    await _storage.addFavorite('product_5');
    await _storage.toggleFavorite('article_1'); // Remove

    final searches = _storage.getRecentSearches();
    final favorites = _storage.getFavoriteIds();

    _setStatus(
      '🔍 Recent Searches: $searches\n\n'
      '⭐ Favorites: $favorites\n'
      '  Is "article_1" favorite: ${_storage.isFavorite("article_1")}\n'
      '  Is "article_2" favorite: ${_storage.isFavorite("article_2")}',
    );
  }

  Future<void> _testPreferences() async {
    await _storage.setNotificationsEnabled(true);
    await _storage.setFontSize(16.0);
    await _storage.setLocale('en_US');
    await _storage.setBiometricEnabled(false);

    _setStatus(
      '🎨 User Preferences:\n'
      '  Theme: ${_storage.getThemeMode()}\n'
      '  Locale: ${_storage.getLocale()}\n'
      '  Notifications: ${_storage.getNotificationsEnabled()}\n'
      '  Font Size: ${_storage.getFontSize()}\n'
      '  Biometric: ${_storage.getBiometricEnabled()}\n'
      '  First Launch: ${_storage.isFirstLaunch}\n'
      '  Onboarding Done: ${_storage.isOnboardingComplete}',
    );
  }

  Future<void> _testSync() async {
    final needsSync = _storage.needsSync();
    await _storage.setLastSyncTime(DateTime.now());

    _setStatus(
      '🔄 Sync Status:\n'
      '  Needed sync before: $needsSync\n'
      '  Last sync: ${_storage.getLastSyncTime()}\n'
      '  Needs sync now: ${_storage.needsSync()}',
    );
  }

  Future<void> _debugStorage() async {
    _storage.printAllStoredData();
    _setStatus(
      '🐛 Debug Info:\n'
      '  Total stored keys: ${_storage.storedKeysCount}\n'
      '  Keys: ${_storage.getAllStoredKeys().keys.join(", ")}\n\n'
      '(Full data printed to console)',
    );
  }

  Future<void> _clearExpiredCache() async {
    await _storage.clearExpiredCache();
    _setStatus('🧹 Expired cache cleared!');
  }

  Future<void> _simulateLogout() async {
    await _storage.logout();
    _setStatus(
      '🚪 Logged out!\n'
      '  Authenticated: ${_storage.isAuthenticated}\n'
      '  User: ${_storage.getUserProfile()}\n'
      '  Theme preserved: ${_storage.getThemeMode()}\n'
      '  Onboarding preserved: ${_storage.isOnboardingComplete}',
    );
  }

  Future<void> _clearAll() async {
    await _storage.clearAll();
    _setStatus('💥 All data cleared!');
  }

  @override
  Widget build(BuildContext context) {
    if (!_initialized) {
      return const Scaffold(
        body: Center(child: CircularProgressIndicator()),
      );
    }

    return Scaffold(
      appBar: AppBar(
        title: const Text('Storage Manager Demo'),
        actions: [
          PopupMenuButton<String>(
            onSelected: (value) async {
              switch (value) {
                case 'light':
                  await _storage.setThemeMode('light');
                  widget.onThemeChanged(ThemeMode.light);
                  break;
                case 'dark':
                  await _storage.setThemeMode('dark');
                  widget.onThemeChanged(ThemeMode.dark);
                  break;
                case 'system':
                  await _storage.setThemeMode('system');
                  widget.onThemeChanged(ThemeMode.system);
                  break;
              }
            },
            itemBuilder: (context) => [
              const PopupMenuItem(value: 'light', child: Text('Light Theme')),
              const PopupMenuItem(value: 'dark', child: Text('Dark Theme')),
              const PopupMenuItem(
                  value: 'system', child: Text('System Theme')),
            ],
            icon: const Icon(Icons.palette),
          ),
        ],
      ),
      body: Column(
        children: [
          // Status display
          if (_statusMessage.isNotEmpty)
            Container(
              width: double.infinity,
              constraints: const BoxConstraints(maxHeight: 200),
              margin: const EdgeInsets.all(12),
              padding: const EdgeInsets.all(12),
              decoration: BoxDecoration(
                color: Theme.of(context)
                    .colorScheme
                    .surfaceContainerHighest,
                borderRadius: BorderRadius.circular(12),
                border: Border.all(
                  color: Theme.of(context).colorScheme.outline.withOpacity(0.3),
                ),
              ),
              child: SingleChildScrollView(
                child: Text(
                  _statusMessage,
                  style: TextStyle(
                    fontFamily: 'monospace',
                    fontSize: 12,
                    color: Theme.of(context).colorScheme.onSurface,
                  ),
                ),
              ),
            ),

          // Action buttons
          Expanded(
            child: ListView(
              padding: const EdgeInsets.symmetric(horizontal: 12),
              children: [
                _buildSectionHeader('Authentication'),
                _buildActionTile(
                  icon: Icons.login,
                  title: 'Simulate Login',
                  subtitle: 'Save auth tokens & user profile',
                  onTap: _simulateLogin,
                ),
                _buildActionTile(
                  icon: Icons.person,
                  title: 'Read User Data',
                  subtitle: 'Get profile & token info',
                  onTap: _readUserData,
                ),
                _buildActionTile(
                  icon: Icons.logout,
                  title: 'Simulate Logout',
                  subtitle: 'Clear auth data, keep preferences',
                  onTap: _simulateLogout,
                  color: Colors.orange,
                ),

                _buildSectionHeader('Configuration'),
                _buildActionTile(
                  icon: Icons.settings,
                  title: 'Save App Config',
                  subtitle: 'API URL, feature flags, etc.',
                  onTap: _saveAppConfig,
                ),
                _buildActionTile(
                  icon: Icons.tune,
                  title: 'Test Preferences',
                  subtitle: 'Theme, locale, notifications, etc.',
                  onTap: _testPreferences,
                ),

                _buildSectionHeader('Data & Cache'),
                _buildActionTile(
                  icon: Icons.cached,
                  title: 'Test Caching',
                  subtitle: 'Cache strings, JSON, lists with TTL',
                  onTap: _testCaching,
                ),
                _buildActionTile(
                  icon: Icons.cloud_off,
                  title: 'Test Offline Data',
                  subtitle: 'Save & retrieve offline content',
                  onTap: _testOfflineData,
                ),
                _buildActionTile(
                  icon: Icons.search,
                  title: 'Test Search & Favorites',
                  subtitle: 'Recent searches, favorite items',
                  onTap: _testSearchAndFavorites,
                ),
                _buildActionTile(
                  icon: Icons.sync,
                  title: 'Test Sync',
                  subtitle: 'Check & update sync timestamps',
                  onTap: _testSync,
                ),

                _buildSectionHeader('Maintenance'),
                _buildActionTile(
                  icon: Icons.bug_report,
                  title: 'Debug Storage',
                  subtitle: 'Print all stored keys & values',
                  onTap: _debugStorage,
                ),
                _buildActionTile(
                  icon: Icons.cleaning_services,
                  title: 'Clear Expired Cache',
                  subtitle: 'Remove only expired cache entries',
                  onTap: _clearExpiredCache,
                ),
                _buildActionTile(
                  icon: Icons.delete_forever,
                  title: 'Clear All Data',
                  subtitle: 'Remove everything from storage',
                  onTap: _clearAll,
                  color: Colors.red,
                ),
                const SizedBox(height: 20),
              ],
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildSectionHeader(String title) {
    return Padding(
      padding: const EdgeInsets.only(top: 16, bottom: 8, left: 4),
      child: Text(
        title.toUpperCase(),
        style: TextStyle(
          fontSize: 12,
          fontWeight: FontWeight.bold,
          color: Theme.of(context).colorScheme.primary,
          letterSpacing: 1.2,
        ),
      ),
    );
  }

  Widget _buildActionTile({
    required IconData icon,
    required String title,
    required String subtitle,
    required VoidCallback onTap,
    Color? color,
  }) {
    return Card(
      margin: const EdgeInsets.symmetric(vertical: 3),
      child: ListTile(
        leading: Icon(icon, color: color ?? Theme.of(context).colorScheme.primary),
        title: Text(
          title,
          style: TextStyle(
            fontWeight: FontWeight.w600,
            color: color,
          ),
        ),
        subtitle: Text(subtitle, style: const TextStyle(fontSize: 12)),
        trailing: const Icon(Icons.play_arrow, size: 20),
        onTap: onTap,
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(12)),
      ),
    );
  }
}